package com.secman.cli.commands

import com.secman.cli.config.ConfigLoader
import com.secman.crowdstrike.client.CrowdStrikeApiClient
import com.secman.crowdstrike.dto.DeviceType
import com.secman.crowdstrike.dto.FalconConfigDto
import com.secman.crowdstrike.exception.AuthenticationException
import com.secman.crowdstrike.exception.CrowdStrikeException
import com.secman.crowdstrike.exception.NotFoundException
import com.secman.crowdstrike.exception.RateLimitException
import com.secman.dto.CrowdStrikeVulnerabilityBatchDto
import com.secman.dto.VulnerabilityDto
import com.secman.service.CrowdStrikeVulnerabilityImportService
import io.micronaut.context.ApplicationContext
import org.slf4j.LoggerFactory

/**
 * Servers command for querying CrowdStrike server vulnerabilities with auto-import
 *
 * Usage:
 *   secman query servers [options]
 *
 * Functionality:
 * - Query CrowdStrike Falcon API for server vulnerabilities (device type: SERVER)
 * - Filter by severity (HIGH, CRITICAL) and days open (>=30 by default)
 * - Optionally filter by specific hostnames
 * - Automatically import discovered servers as Asset records with vulnerabilities
 * - Support dry-run mode (query without importing)
 * - Support verbose logging
 *
 * Feature: 032-servers-query-import, 073-cli-direct-db
 */
class ServersCommand {
    private val log = LoggerFactory.getLogger(ServersCommand::class.java)
    private val configLoader = ConfigLoader()
    private val appContext = ApplicationContext.run()
    private val apiClient: CrowdStrikeApiClient = appContext.getBean(CrowdStrikeApiClient::class.java)
    private val importService: CrowdStrikeVulnerabilityImportService = appContext.getBean(CrowdStrikeVulnerabilityImportService::class.java)

    // Command-line options
    var hostnames: List<String>? = null  // Optional hostname filter (FR-003)
    var deviceType: String = "SERVER"    // Device type filter (FR-002)
    var severity: String = "HIGH,CRITICAL"  // Severity filter (FR-004)
    var minDaysOpen: Int = 30            // Minimum days open filter (FR-004)
    var dryRun: Boolean = false          // Dry-run mode (FR-005)
    var save: Boolean = false            // Save to database (direct access)
    var verbose: Boolean = false         // Verbose logging (FR-009)
    var clientId: String? = null         // CrowdStrike client ID (optional override)
    var clientSecret: String? = null     // CrowdStrike client secret (optional override)
    var limit: Int = 800                 // Page size for pagination
    var lastSeenDays: Int = 0            // Only include devices seen within N days (0 = all devices)

    /**
     * Execute the servers query command
     *
     * @return Exit code (0 = success, 1 = error)
     */
    fun execute(): Int {
        return try {
            // Validate and parse device type (case-insensitive)
            val parsedDeviceType = try {
                DeviceType.fromString(deviceType)
            } catch (e: IllegalArgumentException) {
                System.err.println("Error: ${e.message}")
                return 1
            }

            // Always show which device type is being queried
            System.out.println("Device type: ${parsedDeviceType.name}")

            if (verbose) {
                log.info("Starting query with filters: deviceType={}, severity={}, minDaysOpen={}, lastSeenDays={}, hostnames={}",
                    parsedDeviceType.name, severity, minDaysOpen, lastSeenDays, hostnames?.joinToString(",") ?: "ALL")
            }

            // Load or override configuration
            val config = if (clientId != null && clientSecret != null) {
                FalconConfigDto(
                    clientId = clientId!!,
                    clientSecret = clientSecret!!
                )
            } else {
                configLoader.loadConfig()
            }

            if (verbose) {
                log.info("Configuration loaded successfully")
            }

            // Query CrowdStrike API with filters
            System.out.println("Querying CrowdStrike for ${parsedDeviceType.displayName()}...")
            if (verbose) {
                System.out.println("Filters: device type=${parsedDeviceType.name}, severity=$severity, min days open=$minDaysOpen, last seen days=${if (lastSeenDays > 0) lastSeenDays else "all"}")
                if (hostnames != null) {
                    System.out.println("Hostnames: ${hostnames!!.joinToString(", ")}")
                }
            }

            // When --save is specified and no specific hostnames, use streaming mode
            // to avoid holding all vulnerabilities in memory at once
            if (save && hostnames.isNullOrEmpty()) {
                System.out.println("Querying and importing in streaming mode...")

                var totalServersProcessed = 0
                var totalServersCreated = 0
                var totalServersUpdated = 0
                var totalVulnsImported = 0
                var totalVulnsWithPatchDate = 0
                var totalVulnsSkipped = 0
                val allErrors = mutableListOf<String>()
                var streamBatchNum = 0

                val totalVulns = apiClient.queryServersWithFiltersStreaming(
                    deviceType = deviceType,
                    severity = severity,
                    minDaysOpen = minDaysOpen,
                    config = config,
                    limit = limit,
                    lastSeenDays = lastSeenDays,
                    deviceBatchSize = 200
                ) { batchVulns ->
                    streamBatchNum++
                    val byHostname = batchVulns.groupBy { it.hostname }
                    System.out.println("  Stream batch $streamBatchNum: ${batchVulns.size} vulns across ${byHostname.size} hosts")

                    val batches = byHostname.map { (hostname, vulns) ->
                        val firstVuln = vulns.firstOrNull()
                        CrowdStrikeVulnerabilityBatchDto(
                            hostname = hostname,
                            groups = null,
                            cloudAccountId = firstVuln?.cloudAccountId,
                            cloudInstanceId = firstVuln?.cloudInstanceId,
                            adDomain = firstVuln?.adDomain,
                            osVersion = null,
                            ip = firstVuln?.ip,
                            vulnerabilities = vulns.map { vuln ->
                                VulnerabilityDto(
                                    cveId = vuln.cveId ?: "",
                                    severity = vuln.severity,
                                    affectedProduct = vuln.affectedProduct,
                                    daysOpen = parseDaysOpenToInt(vuln.daysOpen),
                                    patchPublicationDate = vuln.patchPublicationDate
                                )
                            }
                        )
                    }

                    val result = importService.importServerVulnerabilities(batches, "CLI", triggerRefresh = false)
                    totalServersProcessed += result.serversProcessed
                    totalServersCreated += result.serversCreated
                    totalServersUpdated += result.serversUpdated
                    totalVulnsImported += result.vulnerabilitiesImported
                    totalVulnsWithPatchDate += result.vulnerabilitiesWithPatchDate
                    totalVulnsSkipped += result.vulnerabilitiesSkipped
                    allErrors.addAll(result.errors)
                }

                if (totalVulns == 0) {
                    System.out.println("No vulnerabilities found matching criteria")
                    return 0
                }

                val deviceLabel = parsedDeviceType.displayName().replaceFirstChar { it.uppercase() }
                System.out.println("\n--- Import Statistics ---")
                System.out.println("$deviceLabel processed: $totalServersProcessed")
                System.out.println("  - New $deviceLabel created: $totalServersCreated")
                System.out.println("  - Existing $deviceLabel updated: $totalServersUpdated")
                System.out.println("Vulnerabilities imported: $totalVulnsImported")
                System.out.println("  - With patch publication date: $totalVulnsWithPatchDate")
                System.out.println("Vulnerabilities skipped: $totalVulnsSkipped")

                if (allErrors.isNotEmpty()) {
                    System.err.println("\n--- Errors (${allErrors.size}) ---")
                    allErrors.take(20).forEach { error ->
                        System.err.println("  - $error")
                    }
                    if (allErrors.size > 20) {
                        System.err.println("  ... and ${allErrors.size - 20} more errors")
                    }
                }

                return if (allErrors.isNotEmpty()) 1 else 0
            }

            // Non-streaming mode: query all at once (for dry-run, display, or hostname-specific queries)
            val response = apiClient.queryServersWithFilters(
                hostnames = hostnames,
                deviceType = deviceType,
                severity = severity,
                minDaysOpen = minDaysOpen,
                config = config,
                limit = limit,
                lastSeenDays = lastSeenDays
            )

            System.out.println("Found ${response.vulnerabilities.size} vulnerabilities across ${parsedDeviceType.displayName()}")

            if (response.vulnerabilities.isEmpty()) {
                System.out.println("No vulnerabilities found matching criteria")
                return 0
            }

            // Group vulnerabilities by hostname for display
            val vulnerabilitiesByHostname = response.vulnerabilities.groupBy { it.hostname }
            System.out.println("${parsedDeviceType.displayName().replaceFirstChar { it.uppercase() }} with vulnerabilities: ${vulnerabilitiesByHostname.size}")

            if (verbose) {
                vulnerabilitiesByHostname.forEach { (hostname, vulns) ->
                    System.out.println("  - $hostname: ${vulns.size} vulnerabilities")
                }
            }

            // Dry-run mode: skip import
            if (dryRun) {
                System.out.println("\n[DRY-RUN MODE] Would import ${vulnerabilitiesByHostname.size} ${parsedDeviceType.displayName()} with ${response.vulnerabilities.size} vulnerabilities")
                return 0
            }

            // Skip import if --save not specified
            if (!save) {
                System.out.println("\nQuery completed successfully. Use --save to import directly to database.")
                return 0
            }

            // Import directly to database via import service (hostname-specific queries)
            System.out.println("\nImporting to database...")

            // Map CrowdStrike DTOs to backend batch DTOs
            val batches = vulnerabilitiesByHostname.map { (hostname, vulns) ->
                val firstVuln = vulns.firstOrNull()
                CrowdStrikeVulnerabilityBatchDto(
                    hostname = hostname,
                    groups = null,
                    cloudAccountId = firstVuln?.cloudAccountId,
                    cloudInstanceId = firstVuln?.cloudInstanceId,
                    adDomain = firstVuln?.adDomain,
                    osVersion = null,
                    ip = firstVuln?.ip,
                    vulnerabilities = vulns.map { vuln ->
                        VulnerabilityDto(
                            cveId = vuln.cveId ?: "",
                            severity = vuln.severity,
                            affectedProduct = vuln.affectedProduct,
                            daysOpen = parseDaysOpenToInt(vuln.daysOpen),
                            patchPublicationDate = vuln.patchPublicationDate
                        )
                    }
                )
            }

            val result = importService.importServerVulnerabilities(batches, "CLI")

            // Display import statistics
            val deviceLabel = parsedDeviceType.displayName().replaceFirstChar { it.uppercase() }
            System.out.println("\n--- Import Statistics ---")
            System.out.println("$deviceLabel processed: ${result.serversProcessed}")
            System.out.println("  - New $deviceLabel created: ${result.serversCreated}")
            System.out.println("  - Existing $deviceLabel updated: ${result.serversUpdated}")
            System.out.println("Vulnerabilities imported: ${result.vulnerabilitiesImported}")
            System.out.println("  - With patch publication date: ${result.vulnerabilitiesWithPatchDate}")
            System.out.println("Vulnerabilities skipped: ${result.vulnerabilitiesSkipped}")

            if (result.errors.isNotEmpty()) {
                System.err.println("\n--- Errors (${result.errors.size}) ---")
                result.errors.take(20).forEach { error ->
                    System.err.println("  - $error")
                }
                if (result.errors.size > 20) {
                    System.err.println("  ... and ${result.errors.size - 20} more errors")
                }
            }

            if (result.errors.isNotEmpty()) 1 else 0
        } catch (e: NotFoundException) {
            System.err.println()
            val hostnameInfo = if (hostnames != null && hostnames!!.size == 1) {
                "Hostname '${hostnames!!.first()}' not found in CrowdStrike"
            } else {
                "One or more hostnames not found in CrowdStrike"
            }
            System.err.println("Error: $hostnameInfo")
            System.err.println("   The hostname(s) may not exist or may not be monitored by CrowdStrike Falcon.")
            System.err.println("   Please verify the hostnames are correct and the devices are enrolled.")
            1
        } catch (e: AuthenticationException) {
            System.err.println()
            System.err.println("Error: CrowdStrike authentication failed")
            System.err.println("   Please check your CrowdStrike API credentials.")
            System.err.println("   Run 'secman config --show' to verify your configuration.")
            1
        } catch (e: RateLimitException) {
            System.err.println()
            System.err.println("Error: CrowdStrike API rate limit exceeded")
            System.err.println("   Please wait a few minutes before trying again.")
            1
        } catch (e: CrowdStrikeException) {
            System.err.println()
            System.err.println("Error: CrowdStrike API error")
            System.err.println("   ${e.message}")
            if (verbose) {
                e.printStackTrace()
            }
            1
        } catch (e: UnsupportedOperationException) {
            System.err.println("Error: ${e.message}")
            if (verbose) {
                e.printStackTrace()
            }
            1
        } catch (e: IllegalStateException) {
            System.err.println("Error: ${e.message}")
            if (verbose) {
                e.printStackTrace()
            }
            1
        } catch (e: IllegalArgumentException) {
            System.err.println("Error: ${e.message}")
            if (verbose) {
                e.printStackTrace()
            }
            1
        } catch (e: Exception) {
            System.err.println("Error: [${e.javaClass.simpleName}] ${e.message}")
            if (e.cause != null) {
                System.err.println("  Caused by: [${e.cause!!.javaClass.simpleName}] ${e.cause!!.message}")
            }
            if (verbose) {
                e.printStackTrace()
            } else {
                System.err.println("  (Run with --verbose for full stack trace)")
            }
            1
        }
    }

    /**
     * Parse daysOpen string to integer value
     *
     * Handles formats: "526 days" -> 526, "1 day" -> 1, null -> 0
     */
    private fun parseDaysOpenToInt(daysOpen: String?): Int {
        if (daysOpen.isNullOrBlank()) return 0
        return daysOpen.split(" ").firstOrNull()?.toIntOrNull() ?: 0
    }
}

package com.secman.service

import com.secman.config.VulnerabilitySettings
import com.secman.domain.Asset
import com.secman.domain.CrowdStrikeImportHistory
import com.secman.domain.Vulnerability
import com.secman.dto.CrowdStrikeVulnerabilityBatchDto
import com.secman.dto.ImportStatisticsDto
import com.secman.dto.CrowdStrikeImportStatusDto
import com.secman.dto.VulnerabilityDto
import com.secman.repository.AssetRepository
import com.secman.repository.VulnerabilityRepository
import com.secman.repository.CrowdStrikeImportHistoryRepository
import jakarta.inject.Singleton
import jakarta.persistence.EntityManager
import jakarta.persistence.LockModeType
import jakarta.transaction.Transactional
import org.slf4j.LoggerFactory
import java.time.LocalDateTime
import java.time.temporal.ChronoUnit

/**
 * Service for importing CrowdStrike server vulnerabilities with automatic asset creation
 *
 * Provides functionality to:
 * - Find or create Asset records from CrowdStrike server data
 * - Import vulnerabilities with transactional replace pattern (delete old + insert new)
 * - Track import statistics (servers created/updated, vulnerabilities imported/skipped)
 * - Handle per-server transactions with rollback on failure
 * - Preserve existing asset metadata (owner, description, workgroups) when reusing assets
 *
 * Feature: 032-servers-query-import
 * Tasks: T019, T020, T021, T022
 * Spec reference: FR-008, FR-010, FR-011, FR-012, FR-013, FR-015
 */
@Singleton
open class CrowdStrikeVulnerabilityImportService(
    private val assetRepository: AssetRepository,
    private val vulnerabilityRepository: VulnerabilityRepository,
    private val importHistoryRepository: CrowdStrikeImportHistoryRepository,
    private val materializedViewRefreshService: MaterializedViewRefreshService,
    private val vulnerabilitySettings: VulnerabilitySettings,
    private val entityManager: EntityManager
) {
    private val log = LoggerFactory.getLogger(CrowdStrikeVulnerabilityImportService::class.java)

    /**
     * Provider for self-reference to ensure @Transactional works on internal method calls.
     * Using Provider<T> avoids circular dependency during bean construction.
     * Feature 053: Fix AOP proxy bypass for transactional delete-insert pattern
     */
    @jakarta.inject.Inject
    private lateinit var selfProvider: jakarta.inject.Provider<CrowdStrikeVulnerabilityImportService>

    /**
     * Import batch of server vulnerabilities from CrowdStrike
     *
     * Task: T022
     * Spec reference: FR-008
     *
     * @param batches List of server vulnerability batches
     * @param triggeredBy User/system that triggered the import (for audit trail)
     * @param triggerRefresh Whether to trigger materialized view refresh after import.
     *                       Set to false when importing multiple batches to avoid redundant refreshes.
     *                       The caller should trigger a single refresh after all batches complete.
     * @return ImportStatisticsDto with detailed statistics
     */
    fun importServerVulnerabilities(
        batches: List<CrowdStrikeVulnerabilityBatchDto>,
        triggeredBy: String? = null,
        triggerRefresh: Boolean = true
    ): ImportStatisticsDto {
        log.info("Starting batch import of {} servers", batches.size)

        var serversCreated = 0
        var serversUpdated = 0
        var vulnerabilitiesImported = 0
        var vulnerabilitiesSkipped = 0
        var vulnerabilitiesWithPatchDate = 0
        val uniqueDomains = mutableSetOf<String>()  // Feature 043: Track unique domains
        val errors = mutableListOf<String>()

        for (batch in batches) {
            try {
                // Process each server in its own transaction (FR-010)
                // Use selfProvider.get() to ensure @Transactional is applied via AOP proxy (Feature 053)
                val result = selfProvider.get().importVulnerabilitiesForServer(batch)

                if (result.assetCreated) serversCreated++
                else serversUpdated++

                vulnerabilitiesImported += result.vulnerabilitiesImported
                vulnerabilitiesSkipped += result.vulnerabilitiesSkipped
                vulnerabilitiesWithPatchDate += result.vulnerabilitiesWithPatchDate

                // Track unique domains (Feature 043)
                batch.adDomain?.let { domain ->
                    if (domain.isNotBlank()) {
                        uniqueDomains.add(domain.trim().uppercase())
                        log.trace("Tracked domain: {}", domain.trim().uppercase())
                    }
                }

                log.debug("Imported server '{}': created={}, imported={}, skipped={}, withPatchDate={}, domain={}",
                    batch.hostname, result.assetCreated, result.vulnerabilitiesImported, result.vulnerabilitiesSkipped, result.vulnerabilitiesWithPatchDate, batch.adDomain)
            } catch (e: Exception) {
                val errorMsg = "Failed to import server '${batch.hostname}': ${e.message}"
                log.error(errorMsg, e)
                errors.add(errorMsg)
            }
        }

        val statistics = ImportStatisticsDto(
            serversProcessed = batches.size,
            serversCreated = serversCreated,
            serversUpdated = serversUpdated,
            vulnerabilitiesImported = vulnerabilitiesImported,
            vulnerabilitiesSkipped = vulnerabilitiesSkipped,
            vulnerabilitiesWithPatchDate = vulnerabilitiesWithPatchDate,
            uniqueDomainCount = uniqueDomains.size,  // Feature 043
            discoveredDomains = uniqueDomains.sorted(),  // Feature 043
            errors = errors
        )

        log.info("Batch import completed: processed={}, created={}, updated={}, imported={}, skipped={}, withPatchDate={}, uniqueDomains={}, errors={}",
            batches.size, serversCreated, serversUpdated, vulnerabilitiesImported, vulnerabilitiesSkipped, vulnerabilitiesWithPatchDate, uniqueDomains.size, errors.size)

        recordImportHistory(statistics, triggeredBy)

        // Trigger async materialized view refresh after import (if requested)
        // Feature: 034-outdated-assets, Task: T101
        // Spec reference: FR-005 (async refresh)
        // Note: When importing multiple batches, set triggerRefresh=false to avoid redundant refreshes.
        // The caller should trigger a single refresh after all batches complete.
        if (triggerRefresh && vulnerabilitiesImported > 0) {
            log.info("Triggering materialized view refresh after importing {} vulnerabilities", vulnerabilitiesImported)
            materializedViewRefreshService.triggerAsyncRefresh("CLI Import - $vulnerabilitiesImported vulnerabilities imported")
        } else if (!triggerRefresh && vulnerabilitiesImported > 0) {
            log.debug("Skipping materialized view refresh (triggerRefresh=false, caller will handle)")
        }

        return statistics
    }

    /**
     * Persist import execution metadata for UI consumption.
     */
    private fun recordImportHistory(statistics: ImportStatisticsDto, triggeredBy: String?) {
        try {
            val history = CrowdStrikeImportHistory(
                importedAt = LocalDateTime.now(),
                importedBy = triggeredBy,
                serversProcessed = statistics.serversProcessed,
                serversCreated = statistics.serversCreated,
                serversUpdated = statistics.serversUpdated,
                vulnerabilitiesImported = statistics.vulnerabilitiesImported,
                vulnerabilitiesSkipped = statistics.vulnerabilitiesSkipped,
                vulnerabilitiesWithPatchDate = statistics.vulnerabilitiesWithPatchDate,
                errorCount = statistics.errors.size
            )
            importHistoryRepository.save(history)
            log.info("Recorded CrowdStrike import history entry: {}", history)
        } catch (e: Exception) {
            log.error("Failed to record CrowdStrike import history", e)
        }
    }

    fun getLatestImportStatus(): CrowdStrikeImportStatusDto? {
        return importHistoryRepository.findLatest()
            ?.let { CrowdStrikeImportStatusDto.fromEntity(it) }
    }

    /**
     * Import vulnerabilities for a single server with transactional replace pattern
     *
     * **Duplicate Prevention Strategy (Feature 048):**
     * This method prevents duplicate vulnerability entries by implementing a transactional replace pattern:
     * 1. DELETE all existing vulnerabilities for the asset
     * 2. INSERT new vulnerabilities from the import batch
     * 3. All operations wrapped in @Transactional boundary
     *
     * This approach ensures:
     * - **Idempotency**: Running the same import multiple times produces identical results
     * - **No duplicates**: Each (asset, CVE) combination exists exactly once
     * - **Atomicity**: Either all vulnerabilities are replaced, or none are (on failure)
     * - **Remediation tracking**: Removed CVEs indicate vulnerabilities have been patched
     *
     * The transactional replace pattern is preferred over upsert because:
     * - Simpler logic: No need to detect which records to update vs insert
     * - Accurate remediation: Missing CVEs in new import = vulnerability fixed
     * - Better performance: Bulk delete + bulk insert faster than individual upserts
     * - Cleaner state: No orphaned records from complex merge logic
     *
     * **Important Implementation Detail:**
     * The Asset.vulnerabilities relationship MUST NOT use `cascade = [CascadeType.ALL]` or `orphanRemoval = true`.
     * Manual delete-insert operations conflict with JPA cascade behavior, causing newly inserted
     * vulnerabilities to be cascade-deleted when the transaction commits. This service performs
     * explicit vulnerability deletion via `vulnerabilityRepository.deleteByAssetId()` before insertion.
     *
     * Tasks: T021, T024, T025, T026
     * Spec reference: FR-010, FR-011, Feature 048
     *
     * @param batch Server vulnerability batch containing hostname and vulnerabilities
     * @return ServerImportResult with statistics (vulnerabilities imported/skipped, asset created/updated)
     */
    @Transactional
    open fun importVulnerabilitiesForServer(batch: CrowdStrikeVulnerabilityBatchDto): ServerImportResult {
        log.debug("Importing vulnerabilities for server: {}", batch.hostname)

        // Feature 053: Duplicate Asset Cleanup
        // Instead of strict exact match, we look for potential duplicates (FQDN vs Shortname)
        val shortName = batch.hostname.substringBefore(".")
        val candidates = assetRepository.findPotentialDuplicates(shortName)

        val (asset, isNewAsset) = if (candidates.isNotEmpty()) {
            // Pick best match: exact match first, or the one with content, or just the first one
            val bestMatch = candidates.find { it.name.equals(batch.hostname, ignoreCase = true) } 
                           ?: candidates.first()

            // Clean up: We will delete vulnerabilities for ALL candidates to avoid inflation
            // The "best match" will get new vulnerabilities populated below

            Pair(updateAsset(bestMatch, batch), false)
        } else {
            Pair(createNewAsset(batch), true)
        }

        // Delete existing vulnerabilities for this asset AND any duplicates
        // This ensures that "stale" duplicate assets don't contribute to inflated counts
        val assetIdsToClean = if (candidates.isNotEmpty()) {
            candidates.mapNotNull { it.id }
        } else {
            listOf(asset.id!!)
        }

        var deletedCount = 0
        for (id in assetIdsToClean) {
            // Lock asset to prevent concurrent import races
            entityManager.find(Asset::class.java, id, LockModeType.PESSIMISTIC_WRITE)
            val count = vulnerabilityRepository.deleteByAssetId(id)
            deletedCount += count
        }

        if (deletedCount > 0) {
            log.debug("Deleted {} existing vulnerabilities for asset '{}' (and {} duplicates)", 
                deletedCount, asset.name, assetIdsToClean.size - 1)
        }

        // Filter vulnerabilities: require CVE ID and optionally require patch publication date
        // Combined into a single pass to reduce intermediate list allocations (memory optimization)
        val requirePatchDate = vulnerabilitySettings.requirePatchPublicationDate
        var vulnsWithCve = batch.vulnerabilities.filter { vuln ->
            !vuln.cveId.isNullOrBlank() && (!requirePatchDate || vuln.patchPublicationDate != null)
        }
        val skippedCount = batch.vulnerabilities.size - vulnsWithCve.size

        if (skippedCount > 0) {
            log.debug("Skipped {} vulnerabilities (no CVE ID{}) for asset '{}'",
                skippedCount, if (requirePatchDate) " or no patch publication date" else "", asset.name)
        }

        // Feature 054: Deduplicate by (CVE ID, affected product) before inserting
        // CrowdStrike API may return true duplicates from overlapping pagination batches
        // We keep the one with the highest daysOpen value (oldest occurrence)
        // Different products for the same CVE are preserved as separate entries
        val beforeDedup = vulnsWithCve.size
        vulnsWithCve = vulnsWithCve
            .groupBy { Pair(it.cveId, it.affectedProduct) }
            .map { (_, duplicates) -> duplicates.maxByOrNull { it.daysOpen } ?: duplicates.first() }

        val dedupCount = beforeDedup - vulnsWithCve.size
        if (dedupCount > 0) {
            log.info("Deduplicated {} duplicate (CVE, product) entries for asset '{}' ({} -> {} unique)",
                dedupCount, asset.name, beforeDedup, vulnsWithCve.size)
        }

        // Create new vulnerability records (T021)
        // importTimestamp is the same for all vulnerabilities in this batch (used for "current" query)
        val importTimestamp = LocalDateTime.now()
        var vulnerabilitiesWithPatchDateCount = 0
        val vulnerabilities = vulnsWithCve.map { vulnDto ->
            // Track vulnerabilities with patch publication date
            if (vulnDto.patchPublicationDate != null) {
                vulnerabilitiesWithPatchDateCount++
            }

            // Calculate scan timestamp and days open
            // scanTimestamp represents when the vulnerability was discovered (for accurate overdue calculation)
            // importTimestamp represents when this data was imported (for "current" query grouping)
            val (scanTimestamp, daysOpenText) = if (vulnerabilitySettings.usePatchPublicationDate && vulnDto.patchPublicationDate != null) {
                // Use patch publication date as the reference timestamp (Feature 041)
                val patchDate = vulnDto.patchPublicationDate
                val daysFromPatch = ChronoUnit.DAYS.between(patchDate, importTimestamp).toInt()
                val daysText = if (daysFromPatch == 1) "1 day" else "$daysFromPatch days"

                log.trace("Using patch publication date for CVE {}: patch_date={}, days_from_patch={}",
                    vulnDto.cveId, patchDate, daysFromPatch)

                Pair(patchDate, daysText)  // Use patch date as scanTimestamp
            } else {
                // Calculate discovery timestamp from days_open (working backwards from now)
                val discoveryTimestamp = importTimestamp.minusDays(vulnDto.daysOpen.toLong())
                val daysText = "${vulnDto.daysOpen} days"
                Pair(discoveryTimestamp, daysText)  // Use calculated discovery date as scanTimestamp
            }

            Vulnerability(
                asset = asset,
                vulnerabilityId = vulnDto.cveId,
                cvssSeverity = vulnDto.severity,
                vulnerableProductVersions = vulnDto.affectedProduct,
                daysOpen = daysOpenText,
                scanTimestamp = scanTimestamp,
                importTimestamp = importTimestamp,
                patchPublicationDate = vulnDto.patchPublicationDate
            )
        }

        // Save vulnerabilities in chunks to prevent Hibernate first-level cache from growing unbounded
        // For large imports (e.g., 2000+ vulns per server), chunking with flush/clear reduces memory pressure
        if (vulnerabilities.isNotEmpty()) {
            val chunkSize = 500
            if (vulnerabilities.size <= chunkSize) {
                vulnerabilityRepository.saveAll(vulnerabilities)
            } else {
                vulnerabilities.chunked(chunkSize).forEachIndexed { index, chunk ->
                    vulnerabilityRepository.saveAll(chunk)
                    entityManager.flush()
                    entityManager.clear()
                    // Re-attach the asset entity after clear() so subsequent chunks can reference it
                    entityManager.merge(asset)
                    log.trace("Saved vulnerability chunk {}/{} for asset '{}'",
                        index + 1, (vulnerabilities.size + chunkSize - 1) / chunkSize, asset.name)
                }
            }
            log.debug("Created {} new vulnerabilities for asset '{}' ({} with patch publication date)",
                vulnerabilities.size, asset.name, vulnerabilitiesWithPatchDateCount)
        }

        return ServerImportResult(
            assetCreated = isNewAsset,
            vulnerabilitiesImported = vulnerabilities.size,
            vulnerabilitiesSkipped = skippedCount,
            vulnerabilitiesWithPatchDate = vulnerabilitiesWithPatchDateCount
        )
    }

    private fun createNewAsset(batch: CrowdStrikeVulnerabilityBatchDto): Asset {
        val newAsset = Asset(
            name = batch.hostname,
            type = "SERVER",  // FR-002
            owner = "CrowdStrike Import",  // FR-012
            description = null,
            ip = batch.ip?.takeIf { it.isNotBlank() },
            groups = batch.groups?.takeIf { it.isNotBlank() },
            cloudAccountId = batch.cloudAccountId?.takeIf { it.isNotBlank() },
            cloudInstanceId = batch.cloudInstanceId?.takeIf { it.isNotBlank() },
            adDomain = batch.adDomain?.takeIf { it.isNotBlank() },
            osVersion = batch.osVersion?.takeIf { it.isNotBlank() },
            lastSeen = LocalDateTime.now(),
            manualCreator = null,  // Not manually created
            scanUploader = null    // Not from scan upload
        )

        val created = assetRepository.save(newAsset)
        log.debug("Created new asset: {} (id={})", batch.hostname, created.id)
        return created
    }

    private fun updateAsset(existing: Asset, batch: CrowdStrikeVulnerabilityBatchDto): Asset {
        // Smart update: Only modify fields that have changed (Feature 043: US3)
        var hasChanges = false
        val changedFields = mutableListOf<String>()

        // Compare and update IP
        val newIp = batch.ip?.takeIf { it.isNotBlank() }
        if (newIp != null && newIp != existing.ip) {
            log.debug("IP changed for {}: {} -> {}", batch.hostname, existing.ip, newIp)
            existing.ip = newIp
            hasChanges = true
            changedFields.add("ip")
        }

        // Compare and update groups
        val newGroups = batch.groups?.takeIf { it.isNotBlank() }
        if (newGroups != null && newGroups != existing.groups) {
            log.debug("Groups changed for {}: {} -> {}", batch.hostname, existing.groups, newGroups)
            existing.groups = newGroups
            hasChanges = true
            changedFields.add("groups")
        }

        // Compare and update cloud account ID
        val newCloudAccountId = batch.cloudAccountId?.takeIf { it.isNotBlank() }
        if (newCloudAccountId != null && newCloudAccountId != existing.cloudAccountId) {
            log.debug("Cloud account ID changed for {}: {} -> {}", batch.hostname, existing.cloudAccountId, newCloudAccountId)
            existing.cloudAccountId = newCloudAccountId
            hasChanges = true
            changedFields.add("cloudAccountId")
        }

        // Compare and update cloud instance ID
        val newCloudInstanceId = batch.cloudInstanceId?.takeIf { it.isNotBlank() }
        if (newCloudInstanceId != null && newCloudInstanceId != existing.cloudInstanceId) {
            log.debug("Cloud instance ID changed for {}: {} -> {}", batch.hostname, existing.cloudInstanceId, newCloudInstanceId)
            existing.cloudInstanceId = newCloudInstanceId
            hasChanges = true
            changedFields.add("cloudInstanceId")
        }

        // Compare and update AD domain (case-insensitive, normalized to lowercase by @PreUpdate)
        val newAdDomain = batch.adDomain?.takeIf { it.isNotBlank() }
        if (newAdDomain != null && newAdDomain.lowercase() != existing.adDomain?.lowercase()) {
            log.debug("AD domain changed for {}: {} -> {}", batch.hostname, existing.adDomain, newAdDomain)
            existing.adDomain = newAdDomain
            hasChanges = true
            changedFields.add("adDomain")
        }

        // Compare and update OS version
        val newOsVersion = batch.osVersion?.takeIf { it.isNotBlank() }
        if (newOsVersion != null && newOsVersion != existing.osVersion) {
            log.debug("OS version changed for {}: {} -> {}", batch.hostname, existing.osVersion, newOsVersion)
            existing.osVersion = newOsVersion
            hasChanges = true
            changedFields.add("osVersion")
        }

        // Always update lastSeen
        existing.lastSeen = LocalDateTime.now()

        // Only write to database if fields changed
        return if (hasChanges) {
            existing.updatedAt = LocalDateTime.now()
            assetRepository.update(existing)
            log.info("Updated asset '{}' (id={}): changed fields: {}", batch.hostname, existing.id, changedFields.joinToString(", "))
            existing
        } else {
            log.debug("No changes for asset '{}' (id={}), skipping database write", batch.hostname, existing.id)
            existing
        }
    }
}

